import "core-js/modules/es.array.push.js";
import "core-js/modules/es.iterator.constructor.js";
import "core-js/modules/es.iterator.filter.js";
import "core-js/modules/es.iterator.find.js";
import "core-js/modules/es.iterator.for-each.js";
import "core-js/modules/es.iterator.map.js";
import "core-js/modules/web.dom-exception.stack.js";
import { getAccount } from '../api/Account.js';
import { getAllSubjects } from '../api/Subjects.js';
import Sidebar from '../components/Sidebar.vue';
export default {
  name: 'Subjects',
  components: {
    Sidebar
  },
  data() {
    return {
      userName: 'Loading...',
      userLevel: 1,
      userId: null,
      searchQuery: '',
      selectedFilter: 'all',
      selectedCategory: 'all',
      viewMode: 'grid',
      categories: [],
      subjects: [],
      featuredSubjects: [],
      learningPaths: [],
      loading: true,
      error: null
    };
  },
  computed: {
    filteredSubjects() {
      let filtered = this.subjects;

      // Filter by category
      if (this.selectedCategory !== 'all') {
        filtered = filtered.filter(subject => subject.category === this.selectedCategory);
      }

      // Filter by status
      if (this.selectedFilter !== 'all') {
        filtered = filtered.filter(subject => subject.status === this.selectedFilter);
      }

      // Filter by search query
      if (this.searchQuery) {
        const query = this.searchQuery.toLowerCase();
        filtered = filtered.filter(subject => subject.name.toLowerCase().includes(query) || subject.description.toLowerCase().includes(query));
      }
      return filtered;
    }
  },
  async mounted() {
    await this.loadSubjectsData();
  },
  methods: {
    getParticleSize(index) {
      const sizes = ['small', 'medium', 'large'];
      return sizes[index % 3];
    },
    getParticleColor(index) {
      const colors = ['blue', 'purple', 'pink', 'cyan'];
      return colors[index % 4];
    },
    getUserIdFromToken() {
      try {
        const token = localStorage.getItem('token');
        if (!token) return null;
        const payload = JSON.parse(atob(token.split('.')[1]));
        return payload.id;
      } catch (error) {
        console.error('Error decoding token:', error);
        return null;
      }
    },
    async loadSubjectsData() {
      try {
        this.loading = true;
        this.error = null;
        const userId = this.getUserIdFromToken();
        if (!userId) {
          throw new Error('No valid user token found');
        }
        this.userId = userId;

        // Load user account data
        const accountData = await getAccount(userId);
        this.userName = accountData.username || 'User';
        this.userLevel = accountData.currentLevel || 1;

        // Load subjects from API
        const subjectsData = await getAllSubjects();
        this.subjects = subjectsData.map(subject => ({
          ...subject,
          status: subject.enrollmentStatus || 'available',
          progress: subject.userProgress || 0,
          bookmarked: subject.isBookmarked || false,
          icon: this.getSubjectIcon(subject.category),
          rating: subject.averageRating || 4.5,
          students: subject.enrolledCount || 0
        }));

        // Generate categories from subjects data
        const categoryMap = new Map();
        categoryMap.set('all', {
          id: 'all',
          name: 'All Subjects',
          icon: 'fas fa-th',
          count: this.subjects.length
        });
        this.subjects.forEach(subject => {
          const category = subject.category;
          if (!categoryMap.has(category)) {
            categoryMap.set(category, {
              id: category,
              name: this.getCategoryDisplayName(category),
              icon: this.getCategoryIcon(category),
              count: 0
            });
          }
          categoryMap.get(category).count++;
        });
        this.categories = Array.from(categoryMap.values());

        // Load featured subjects (could be a separate API endpoint)
        this.featuredSubjects = this.subjects.filter(subject => subject.featured).slice(0, 3).map(subject => ({
          id: subject.id,
          name: subject.name,
          description: subject.description,
          image: subject.imageUrl || 'https://via.placeholder.com/300x200',
          instructor: subject.instructor || 'Instructor',
          price: subject.price || null,
          category: subject.category
        }));

        // Generate learning paths from subjects (could be a separate API endpoint)
        this.learningPaths = this.generateLearningPaths();
      } catch (error) {
        console.error('Error loading subjects data:', error);
        this.error = 'Failed to load subjects data';
        if (error.message.includes('token') || error.response?.status === 401) {
          localStorage.removeItem('token');
          this.$router.push('/login');
        }
      } finally {
        this.loading = false;
      }
    },
    getCategoryName(categoryId) {
      const category = this.categories.find(cat => cat.id === categoryId);
      return category ? category.name : 'All Subjects';
    },
    getStatusIcon(status) {
      switch (status) {
        case 'enrolled':
          return 'fas fa-play-circle';
        case 'completed':
          return 'fas fa-check-circle';
        case 'available':
          return 'fas fa-plus-circle';
        default:
          return 'fas fa-circle';
      }
    },
    getActionClass(status) {
      switch (status) {
        case 'enrolled':
          return 'continue';
        case 'completed':
          return 'review';
        case 'available':
          return 'enroll';
        default:
          return 'enroll';
      }
    },
    getActionIcon(status) {
      switch (status) {
        case 'enrolled':
          return 'fas fa-play';
        case 'completed':
          return 'fas fa-redo';
        case 'available':
          return 'fas fa-plus';
        default:
          return 'fas fa-plus';
      }
    },
    getActionText(status) {
      switch (status) {
        case 'enrolled':
          return 'Continue';
        case 'completed':
          return 'Review';
        case 'available':
          return 'Enroll';
        default:
          return 'Enroll';
      }
    },
    viewSubject(subject) {
      console.log('Viewing subject:', subject.name);
      // Here you would navigate to the subject detail page
      alert(`Viewing ${subject.name}`);
    },
    handleSubjectAction(subject) {
      console.log('Subject action:', subject.status, subject.name);
      switch (subject.status) {
        case 'enrolled':
          alert(`Continuing ${subject.name}`);
          break;
        case 'completed':
          alert(`Reviewing ${subject.name}`);
          break;
        case 'available':
          alert(`Enrolling in ${subject.name}`);
          subject.status = 'enrolled';
          subject.progress = 0;
          break;
      }
    },
    toggleBookmark(subject) {
      subject.bookmarked = !subject.bookmarked;
      console.log('Bookmarked:', subject.name, subject.bookmarked);
    },
    enrollSubject(subject) {
      console.log('Enrolling in featured subject:', subject.name);
      alert(`Enrolling in ${subject.name}`);
    },
    startPath(path) {
      console.log('Starting learning path:', path.name);
      alert(`Starting learning path: ${path.name}`);
    },
    getSubjectIcon(category) {
      const icons = {
        'mathematics': 'fas fa-calculator',
        'science': 'fas fa-flask',
        'language': 'fas fa-language',
        'history': 'fas fa-landmark',
        'arts': 'fas fa-palette',
        'technology': 'fas fa-laptop-code',
        'business': 'fas fa-briefcase'
      };
      return icons[category] || 'fas fa-book';
    },
    getCategoryDisplayName(category) {
      const names = {
        'mathematics': 'Mathematics',
        'science': 'Science',
        'language': 'Languages',
        'history': 'History',
        'arts': 'Arts & Design',
        'technology': 'Technology',
        'business': 'Business'
      };
      return names[category] || category.charAt(0).toUpperCase() + category.slice(1);
    },
    getCategoryIcon(category) {
      const icons = {
        'mathematics': 'fas fa-calculator',
        'science': 'fas fa-flask',
        'language': 'fas fa-language',
        'history': 'fas fa-landmark',
        'arts': 'fas fa-palette',
        'technology': 'fas fa-laptop-code',
        'business': 'fas fa-briefcase'
      };
      return icons[category] || 'fas fa-book';
    },
    generateLearningPaths() {
      return [{
        id: 1,
        name: 'Web Development Fundamentals',
        description: 'Learn the basics of web development from HTML to JavaScript',
        icon: 'fas fa-code',
        duration: '3 months',
        subjects: ['HTML & CSS', 'JavaScript', 'React Basics'],
        subjectCount: 3,
        enrolled: 1250
      }, {
        id: 2,
        name: 'Data Science Journey',
        description: 'Master data analysis and machine learning',
        icon: 'fas fa-chart-line',
        duration: '6 months',
        subjects: ['Statistics', 'Python', 'Machine Learning'],
        subjectCount: 4,
        enrolled: 890
      }];
    },
    logout() {
      localStorage.removeItem('token');
      this.$router.push('/login');
    }
  }
};
